import React, { useState, useEffect } from 'react';
import { Text, View, Image } from 'react-native';
import { useRoute } from '@react-navigation/native';
import { TouchableOpacity } from 'react-native';
import { useNavigation } from '@react-navigation/native';

function PokedexDetails() {
  const route = useRoute();
  const { id } = route.params;
  const [data, setData] = useState(null);
  const navigation = useNavigation();

  useEffect(() => {
    fetch(`https://pokebuildapi.fr/api/v1/pokemon/${id}`)
      .then(response => response.json())
      .then(jsonData => setData(jsonData))
      .catch(error => console.error(error))
  }, []);

  console.log(data.id-1);

  const handlePokemonPress = (pokemonId) => {
    navigation.navigate('PokedexDetails', { id: pokemonId });
  };

  return (
    <>
      {data != null ? (
        <View key={data.id}>
          <Text>{data.name}</Text>
          <Image source={{ uri: data.image }} style={{ width: 200, height: 200 }} />
          <Text>préEvolution :</Text>
          {data.apiPreEvolution && data.apiPreEvolution.name ? (
            <TouchableOpacity onPress={() => handlePokemonPress(data.id - 1)}>
              <Text>{data.apiPreEvolution.name}</Text>
            </TouchableOpacity>
          ) : (
            <Text>aucune</Text>
          )}
          <Text>évolution : {data.apiEvolutions[0] ? data.apiEvolutions[0].name : "aucune"}</Text>
        </View>
      ) : (
        <Text>Chargement des données...</Text>
      )}
    </>
  );
}

export default PokedexDetails;
